// Called from a click handler, not on mount
async function handleSubscribeClick() {
  const reg = await navigator.serviceWorker.ready;
  const permission = await Notification.requestPermission();
  if (permission !== 'granted') return null;
  const sub = await reg.pushManager.subscribe({
    userVisibleOnly: true,
    applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
  });
  await fetch('/api/push/subscribe', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(sub),
  });
  return sub;
}

self.addEventListener('push', (event) => {
  const data = event.data?.json() ?? { title: 'New Notification', body: '' };
  event.waitUntil(
    self.registration.showNotification(data.title, {
      body: data.body,
      icon: '/icons/icon-192x192.png',
      badge: '/icons/badge-72x72.png',
      tag: data.tag,
      data: data.url,
    })
  );
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close(); // required
  const url = event.notification.data || '/';
  event.waitUntil(
    clients.matchAll({ type: 'window' }).then((list) => {
      for (const client of list) {
        if (client.url === url && 'focus' in client) return client.focus();
      }
      return clients.openWindow(url);
    })
  );
});

// lib/vapid.ts
export function urlBase64ToUint8Array(b64: string): Uint8Array {
  const pad = '='.repeat((4 - (b64.length % 4)) % 4);
  const norm = (b64 + pad).replace(/-/g, '+').replace(/_/g, '/');
  const raw = atob(norm);
  const arr = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) arr[i] = raw.charCodeAt(i);
  return arr;
}
// Test: assert Uint8Array length is 65 for a P-256 public key.

// WRONG: await fetch() inside transaction auto-closes it
const tx = db.transaction('requests', 'readwrite');
await tx.store.add(item);
await fetch('/api/sync');        // <-- auto-closes tx
await tx.done;                   // throws: transaction already finished

// Correct: complete the IDB operation first, then fetch
await db.add('requests', item);  // separate transaction per operation
await fetch('/api/sync');        // fetch after IDB is done

// Client: register one-shot sync
if ('serviceWorker' in navigator && 'sync' in ServiceWorkerRegistration.prototype) {
  const reg = await navigator.serviceWorker.ready;
  await reg.sync.register('sync-pending-requests');
}

// Service worker: handle sync
self.addEventListener('sync', (event) => {
  if (event.tag === 'sync-pending-requests') {
    event.waitUntil(replayPendingRequests());
  }
});

// In the page: listen for new SW waiting
navigator.serviceWorker.ready.then((reg) => {
  reg.addEventListener('updatefound', () => {
    const newWorker = reg.installing;
    newWorker?.addEventListener('statechange', () => {
      if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
        showUpdateBanner(() => {
          newWorker.postMessage({ type: 'SKIP_WAITING' });
          window.location.reload();
        });
      }
    });
  });
});
